"""
MKT Original Language Commentary — Psalms chapters 134–139
Run: python3 scripts/zc-original-psalms-134-139.py

Source data used:
- data/interlinear/psalms.json
- data/translation/glossary-hebrew.json (H2617 ḥesed dispute_level=4; H1564 gōlem; H2713 ḥāqar)
- data/translation/draft/mediating/psalms.json

Key decisions in this range:
- Ps 134 is the last of the fifteen Songs of Ascents (šîr hamaʿălôt, Ps 120–134);
  the ʿōśēh šāmayim wāʾāreṣ closing formula (v3) creates a bookend with Ps 121:2 and 124:8
- Ps 135 is a mosaic psalm: vv15–18 adapted from Ps 115:4–8; vv13–14 echo Exod 3:15
- Ps 136: ḥesed rendered "steadfast love" throughout; the 26-verse refrain kî lĕʿôlām ḥasdô
  is a liturgical antiphon — each half-verse was chanted by cantor and congregation in turn
- Ps 137: ʿōlālayik (v9) = your little ones/infants; the imprecation is read in light of Isa 13:16
  and reflects lex talionis applied at the national level, not gratuitous cruelty
- Ps 138: ʾimrātĕkā higdaltā ʿal-kol-šimĕkā (v2b): God's fulfilled promise has exceeded
  even the expectations his reputation had created — not a ranking of word over name
- Ps 139: gōlemî (v16) is a hapax legomenon for the unformed embryo;
  kĕlāyôt (v13) = kidneys as the seat of emotion; šĕʾôl (v8) = realm of the dead, not hell
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: mkt-original for Psalms 134–139 — the final Song of Ascents (134), two great Hallel
#   psalms (135–136), the lament of the exile (137), a Davidic thanksgiving (138), and the great
#   psalm of divine omniscience (139); 91 verses total.
# CHANGE? If commentary/mkt-original/psalms.json structure changes, update load_comm/save_comm.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-original/psalms.json'));
#   [print(ch, len(d[ch])) for ch in [str(i) for i in range(134,140)]]"

PSALMS = {
  "134": {
    "1": '<p><strong>šîr hamaʿălôt</strong> — "a song of the ascents" — the final psalm bearing this superscription, closing the collection that opened at Ps 120. <em>maʿălôt</em> (ascents, steps, goings up) from <em>ʿālāh</em> (to go up, ascend). This last Ascent psalm is unique in its brevity and bidirectional structure: vv1–2 address the temple servants; v3 is their priestly response. <em>bārĕkû YHWH kol-ʿabdê YHWH</em> — "bless the LORD, all servants of the LORD" — <em>bārak</em> in the Piel (bless) is used of both humans blessing God (adoration) and God blessing humans (benefit); here human praise directed toward the divine. <em>ʿabdê YHWH</em> (servants of the LORD) — the term denotes temple personnel, specifically the Levitical night watch who maintained the sanctuary when the festival pilgrims had departed.</p><p><em>šeʿōmĕdîm bĕbêt-YHWH ballêlôt</em> — "who stand in the house of the LORD through the nights" — <em>ʿāmad</em> (to stand) is the technical term for priestly service (Deut 10:8; 17:12). The plural <em>ballêlôt</em> (by night, plural of <em>laylāh</em>) emphasizes continuous nocturnal duty, not a single evening. The night-watch Levites kept vigil, guarded the precincts, and conducted overnight ritual duties (1 Chr 9:27; Neh 11:19).</p>',
    "2": '<p><strong>śĕʾû yĕdêkem qōdeš ûbārĕkû ʾet-YHWH</strong> — "lift your hands toward the holy [place] and bless the LORD" — <em>śāʾû</em> (Qal imperative of <em>nāśāʾ</em>, lift, carry) + <em>yĕdêkem</em> (your hands, dual). The gesture of uplifted hands (<em>nāśāʾ yādayim</em>) is the standard posture of blessing and supplication across the ancient Near East — both petition and praise involve the opened, raised hands (1 Kgs 8:22; Neh 8:6; 1 Tim 2:8). <em>qōdeš</em> (holy, the Holy Place / sanctuary) — the word may be adverbial ("in holiness") or directional ("toward the sanctuary"), pointing the hands toward the inner sanctuary even during the night watch.</p>',
    "3": '<p><strong>yĕbārekĕkā YHWH miṣṣiyyôn ʿōśēh šāmayim wāʾāreṣ</strong> — "may the LORD bless you from Zion — the maker of heaven and earth" — the priestly response to vv1–2. <em>yĕbārekĕkā</em> (jussive, may he bless you) — the blessing flows from the LORD enthroned in Zion. <em>ʿōśēh šāmayim wāʾāreṣ</em> (maker of heaven and earth) — this precise formula closes Psalms 121 (v2) and 124 (v8), and now 134 (v3), creating a structural bracket across the entire Ascents collection. The pilgrim who started with "my help comes from the LORD, maker of heaven and earth" (121:2) ends with the same divine title in a priestly benediction. The one worshipped in Zion is not a local deity but the creator of everything — the cosmic frame holds the pilgrimage together.</p>',
  },
  "135": {
    "1": '<p><strong>hallĕlû-yāh hallĕlû ʾet-šēm YHWH hallĕlû ʿabdê YHWH</strong> — "praise Yah! Praise the name of the LORD! Praise, O servants of the LORD!" — the triple <em>hallĕlû</em> in one verse is emphatic; the imperative plural presses urgency and communal weight. <em>hallĕlû-yāh</em> (praise Yah) combines <em>hālal</em> (to praise, shine, boast) with the shortened divine name <em>Yāh</em>. <em>šēm YHWH</em> (name of the LORD) — in Hebrew thought the name is not merely a label but the person-in-action; to praise the name is to praise YHWH as he has revealed and enacted himself.</p>',
    "2": '<p><strong>šeʿōmĕdîm bĕbêt YHWH bĕḥaṣrôt bêt ʾĕlōhênû</strong> — "who stand in the house of the LORD, in the courts of the house of our God" — <em>ʿāmad</em> (stand) again as the technical term for priestly service (cf. Ps 134:1). The verse mirrors 134:1 deliberately: the servants who stand at night are called to praise. <em>ḥaṣrôt</em> (courts) — the outer courts where the broader assembly gathered; the distinction from the inner house marks the range of the temple complex. <em>ʾĕlōhênû</em> (our God) — the possessive pronoun marks the covenantal relationship distinguishing Israel from those whose gods are foreign.</p>',
    "3": '<p><strong>hallĕlû-yāh kî-ṭôb YHWH zammĕrû lĕšimô kî nāʿîm</strong> — "praise the LORD, for the LORD is good; sing praises to his name, for it is delightful/pleasant" — two grounds for praise: <em>kî-ṭôb</em> (for he is good) — the most fundamental theological assertion, echoing Ps 106:1, 107:1, 118:1, and 136:1; and <em>kî nāʿîm</em> (for it is pleasant/lovely). <em>nāʿîm</em> (pleasant, lovely, from the same root as Naomi\'s name) — praise of YHWH is presented as aesthetically satisfying, not merely obligatory duty.</p>',
    "4": '<p><strong>kî-yaʿăqōb bāḥar lô yāh yiśrāʾēl lisĕgullātô</strong> — "for the LORD chose Jacob as his own, Israel as his prized possession" — <em>bāḥar</em> (Qal perfect, chose) — divine election is the first ground of national praise: praise flows from being chosen. <em>sĕgullāh</em> (H5459) — a treasured possession kept close; the word appears in the covenant-making contexts of Exod 19:5, Deut 7:6, 14:2, and 26:18, always for Israel as YHWH\'s specially held possession among all peoples. <em>lô yāh</em> — "for himself, for Yah" — the election is not for Israel\'s benefit alone but for YHWH\'s purposes and ownership.</p>',
    "5": '<p><strong>kî ʾănî yādaʿtî kî-gādôl YHWH waʾădōnênû mikkol-ʾĕlōhîm</strong> — "for I know that the LORD is great — our Lord stands above every so-called god" — <em>ʾănî yādaʿtî</em> (I personally know) — the shift to first-person singular gives a confessional force; this is not abstract theology but personal knowledge. <em>gādôl YHWH mikkol-ʾĕlōhîm</em> (the LORD is great above all gods) — the superlative comparison does not affirm the existence of other gods but asserts incomparable supremacy (see Exod 18:11 for the same form).</p>',
    "6": '<p><strong>kōl ʾăšer ḥāpēṣ YHWH ʿāśāh bašāmayim ûbāʾāreṣ bāyammîm wĕkol-tĕhōmôt</strong> — "the LORD does whatever he pleases — in heaven and on earth, in the seas and every depth" — <em>kōl ʾăšer ḥāpēṣ ʿāśāh</em> (everything that he delights in he does) — divine sovereignty expressed as unrestricted will. <em>ḥāpēṣ</em> (delight in, desire, take pleasure in) — YHWH\'s actions are not mechanical necessity but volitional delight. The four zones — heaven, earth, seas, depths (<em>tĕhōmôt</em>) — constitute the full created order in its ancient three-tier model, asserting total sovereignty without exception.</p>',
    "7": '<p><strong>maʿăleh nĕśiʾîm miqqĕṣēh hāʾāreṣ bĕrāqîm lammāṭār ʿāśāh môṣēʾ-rûaḥ mēʾôṣĕrōtāyw</strong> — "he draws up clouds from the ends of the earth, makes lightning flash with the rain, and releases the wind from his storehouses" — three participles depict ongoing governance of weather: <em>maʿăleh</em> (causing clouds to ascend), <em>ʿāśāh bĕrāqîm</em> (making lightning), <em>môṣēʾ-rûaḥ</em> (bringing out wind). <em>ʾôṣĕrôt</em> (storehouses, treasuries) — ancient cosmology imagined reserves of rain, wind, and snow held by God (Job 38:22; Jer 10:13). The theological point: weather belongs to YHWH, not Baal the Canaanite storm deity.</p>',
    "8": '<p><strong>šehhikkāh bĕkôrê miṣrayim mēʾādām ʿad-bĕhēmāh</strong> — "he struck down the firstborn of Egypt — both people and animals alike" — <em>hikkāh</em> (Hiphil perfect of <em>nākāh</em>, to strike, smite) — the same verb used throughout the plague narratives (Exod 7–12). The scope <em>mēʾādām ʿad-bĕhēmāh</em> (from human to beast) deliberately echoes Exod 11:5 and 12:12, tying the historical credo exactly to the Passover narrative. The verse moves from creation sovereignty (vv6–7) to redemptive history: the same power governing the cosmos acted in Egypt.</p>',
    "9": '<p><strong>šālaḥ ʾôtôt ûmôpĕtîm bĕtôkēk miṣrayim bĕparʿōh ûbĕkol-ʿăbādāyw</strong> — "he sent miraculous signs and wonders into Egypt — upon Pharaoh and all his servants" — <em>ʾôtôt ûmôpĕtîm</em> (signs and wonders) — the paired formula for the plagues (Deut 4:34; 6:22; 7:19; 26:8); so fixed in the tradition that the Exodus is regularly summarized by this phrase alone. <em>ʿăbādāyw</em> (his servants/officials) — the term for Pharaoh\'s court officials parallels the term for YHWH\'s servants (v1), creating an ironic contrast: the true servants (Israel) versus Pharaoh\'s servile court.</p>',
    "10": '<p><strong>šehhikkāh gôyim rabbîm wĕhārag mĕlākîm ʿăṣûmîm</strong> — "he defeated great nations and put mighty kings to death" — the historical credo moves from Exodus to conquest. <em>rabbîm</em> (great, many) and <em>ʿăṣûmîm</em> (mighty, powerful) — the emphasis on the power of the defeated heightens the contrast with YHWH\'s supreme power. The verse introduces the list of conquered kings in vv11–12.</p>',
    "11": '<p><strong>lĕSîḥôn melek hāʾĕmōrî ûlĕʿôg melek habbāšān wĕlĕkōl mamlĕkôt kĕnāʿan</strong> — "Sihon king of the Amorites, Og king of Bashan, and all the kingdoms of Canaan" — Sihon and Og are the archetypal defeated kings of the conquest narrative (Num 21:21–35; Deut 2–3). They appear together in the historical creeds of Pss 135–136, Neh 9:22, and Deut 31:4. Their defeat east of the Jordan was the first conquest milestone; "all the kingdoms of Canaan" extends the record through the period of Joshua.</p>',
    "12": '<p><strong>wĕnātan ʾarṣām nāḥălāh nāḥălāh lĕyiśrāʾēl ʿammô</strong> — "and gave their land as an inheritance — an inheritance to his people Israel" — the repeated <em>nāḥălāh</em> (inheritance, heritage) — the doubling (first as cognate accusative, then in apposition) is emphatic: the land given is truly and permanently an inheritance. <em>nāḥălāh</em> carries legal and familial weight — not a gift to be returned but a permanent family possession tied to covenant identity (Num 26:52–56; Josh 13–22).</p>',
    "13": '<p><strong>YHWH šimĕkā lĕʿôlām YHWH zikrĕkā lĕdōr-wādōr</strong> — "O LORD, your name endures forever; your memory endures through every generation" — <em>šēm</em> (name) and <em>zēker</em> (memory, memorial, H2143) are paired as near-synonyms: the name is how YHWH is known; the <em>zēker</em> is how he is remembered and re-presented. This verse is a near-quotation of Exod 3:15, where YHWH declares his name to Moses: "this is my name forever, and this is my memorial unto all generations." Psalm 135 explicitly grounds praise of YHWH\'s name in the Sinai self-disclosure.</p>',
    "14": '<p><strong>kî-yādîn YHWH ʿammô wĕʿal-ʿăbādāyw yitnaḥēm</strong> — "the LORD will uphold the cause of his people and will show compassion toward his servants" — <em>yādîn</em> (Qal imperfect of <em>dîn</em>, to judge, vindicate, plead the case of) — the imperfect expresses ongoing and future advocacy; YHWH as juridical defender. <em>yitnaḥēm</em> (Hithpael of <em>nāḥam</em>, to show compassion, relent, be moved to pity) — the Hithpael expresses inner emotional movement; this is not cold judicial process but the compassion of a parent moved for their children (cf. Hos 11:8). The verse closely parallels Deut 32:36.</p>',
    "15": '<p><strong>ʿăṣabbê haggôyim kesep wĕzāhāb maʿăśēh yĕdê ʾādām</strong> — "the idols of the nations are silver and gold — the work of human hands" — this verse opens the anti-idol polemic (vv15–18) adapted from Ps 115:4–8. <em>ʿăṣabbê</em> (idols, from <em>ʿāṣab</em> — to fashion, carve, also to grieve) — the term carries the sense of painful labor producing a lifeless product. <em>maʿăśēh yĕdê ʾādām</em> (work of human hands) — the decisive theological critique: the idol is human manufacture, not divine self-disclosure. What is made cannot be greater than its maker.</p>',
    "16": '<p><strong>peh-lāhem wĕlōʾ yĕdabbērû ʿênayim lāhem wĕlōʾ yirʾû</strong> — "they have mouths, but they cannot speak; they have eyes, but they cannot see" — the parallelism proceeds through the sensory organs: mouth (speech), eyes (sight), ears (hearing, v17), breath (v17). In each case the idol has the anatomical form without the function. In the ancient world, the idol\'s mouth was ritually "opened" in the Babylonian <em>mīs pî</em> ceremony to animate it with divine presence. The psalm denies that any such animation occurs: the opened mouth remains speechless.</p>',
    "17": '<p><strong>ʾoznayim lāhem wĕlōʾ yaʾăzînû ʾap ʾên-yēš-rûaḥ bĕpîhem</strong> — "they have ears, but they do not hear; there is not a breath of air in their mouths" — <em>rûaḥ</em> (spirit/breath/wind) — the word encompasses the animating breath of life (Gen 2:7; Ezek 37:5). The idol has no <em>rûaḥ</em>: it cannot breathe, cannot be animated, cannot respond. In contrast, YHWH breathes life into humans and fills his prophets with his <em>rûaḥ</em>; the divine/idol contrast is precisely the contrast between living <em>rûaḥ</em> and lifeless void.</p>',
    "18": '<p><strong>kĕmôhem yihyû ʿōśêhem kōl ʾăšer bōṭēaḥ bāhem</strong> — "those who make them will become like them — and so will all who trust in them" — the spiritual law: worshippers are conformed to their object of worship. <em>kĕmôhem yihyû</em> (they shall become like them) — those who fashion and trust lifeless, speechless, sightless idols become spiritually mute and blind themselves (cf. Jer 10:14; Hos 9:10). The warning extends from craftsman to truster: the idolater\'s spiritual impoverishment mirrors the idol\'s ontological poverty.</p>',
    "19": '<p><strong>bêt yiśrāʾēl bārĕkû ʾet-YHWH bêt ʾahărōn bārĕkû ʾet-YHWH</strong> — "praise the LORD, O house of Israel! Praise the LORD, O house of Aaron!" — the fourfold call to bless (vv19–21) mirrors the fourfold blessing structure of Ps 115:9–13 and the Aaronic benediction categories. <em>bêt yiśrāʾēl</em> (house of Israel) — the whole covenant people. <em>bêt ʾahărōn</em> (house of Aaron) — the Aaronic priesthood specifically, the descendants of Aaron who officiated in the sanctuary.</p>',
    "20": '<p><strong>bêt hallēwî bārĕkû ʾet-YHWH yirʾê YHWH bārĕkû ʾet-YHWH</strong> — "praise the LORD, O house of Levi! All who fear the LORD, praise the LORD!" — <em>bêt hallēwî</em> (house of Levi) — the broader Levitical tribe, including temple singers, porters, and servants not of Aaronic descent. The four groups form a concentric pattern: all Israel → priests (Aaron) → Levites → God-fearers. <em>yirʾê YHWH</em> (those who fear the LORD) is the same phrase used in Ps 22:23; 115:11, 13 — likely designating a fourth identifiable group that could include devout Gentiles and proselytes beyond ethnic Israel.</p>',
    "21": '<p><strong>bārûk YHWH miṣṣiyyôn šōkēn yĕrûšālāim hallĕlû-yāh</strong> — "praise be to the LORD from Zion — he who makes his home in Jerusalem. Praise the LORD!" — <em>šōkēn</em> (dwelling, making his home, participle of <em>šākan</em>) — the same root as the <em>Miškan</em> (tabernacle) and the later concept of the Shekinah; YHWH is not merely worshipped in Zion but resident there. The closing <em>hallĕlû-yāh</em> creates an envelope with the opening v1, framing the entire psalm as a praise bracket around the historical and theological content of vv4–20. The Davidic covenant — YHWH dwelling in Zion — anchors the cosmic creator\'s presence in a specific place.</p>',
  },
  "136": {
    "1": '<p><strong>hōdû lYHWH kî-ṭôb kî lĕʿôlām ḥasdô</strong> — "give thanks to the LORD, for he is good — for his steadfast love endures forever" — the refrain <em>kî lĕʿôlām ḥasdô</em> (for his steadfast love endures forever) occurs 26 times — once per verse — making this the only biblical psalm with an unbroken antiphonal refrain throughout. <em>ḥesed</em> (H2617, dispute_level 4) — the great covenant term: loving-kindness, steadfast love, covenant loyalty. Its meaning spans loyal love between treaty partners, parental compassion, and God\'s unfailing commitment to his covenant promises. The MKT renders it "steadfast love" throughout to preserve the covenantal force. <em>hōdû</em> (Hiphil imperative of <em>yādāh</em>, to give thanks, confess) — the imperative makes this an active call, not a passive observation. Structurally the psalm moves from creation (vv1–9) to Exodus/wilderness/conquest (vv10–22) to present remembrance and provision (vv23–25) before the closing doxology (v26).</p>',
    "2": '<p><strong>hōdû lĕʾĕlōhê hāʾĕlōhîm kî lĕʿôlām ḥasdô</strong> — "give thanks to the God above all gods — for his steadfast love endures forever" — <em>ʾĕlōhê hāʾĕlōhîm</em> (God of gods) — the superlative construction in Hebrew (noun + same noun in construct) expresses the highest degree: the God who stands supreme over every claim to divinity. This title appears also in Deut 10:17 and Dan 2:47 in similar contexts of absolute cosmic sovereignty.</p>',
    "3": '<p><strong>hōdû lăʾdōnê hāʾădōnîm kî lĕʿôlām ḥasdô</strong> — "give thanks to the Lord who reigns above all lords — for his steadfast love endures forever" — <em>ʾădōnê hāʾădōnîm</em> (Lord of lords) — the second superlative, using <em>ʾādôn</em> (lord, master, sovereign). The three opening verses form a triad: YHWH (personal covenant name, v1), God of gods (cosmic supremacy, v2), Lord of lords (sovereign mastery, v3). In Rev 17:14 and 19:16, "King of kings and Lord of lords" is applied directly to Christ, drawing directly on this language.</p>',
    "4": '<p><strong>lĕʿōśēh niplāʾôt gĕdōlôt lĕbaddô kî lĕʿôlām ḥasdô</strong> — "to him who alone performs great wonders — for his steadfast love endures forever" — <em>niplāʾôt</em> (wonders, marvelous deeds, from <em>pālāʾ</em>, to be extraordinary, surpassing) — the word group used for the Exodus miracles and the incomparable acts of God. <em>lĕbaddô</em> (alone, by himself) — no other agent shares credit for the great wonders. The grammar anticipates the creation hymn: what follows are the great wonders he alone has done.</p>',
    "5": '<p><strong>lĕʿōśēh hašāmayim bitbûnāh kî lĕʿôlām ḥasdô</strong> — "to him who made the heavens with wisdom — for his steadfast love endures forever" — <em>bitbûnāh</em> (with understanding, wisdom, discernment) — <em>tĕbûnāh</em> from <em>bîn</em> (to understand, discern); creation of the heavens is presented as an act of divine intelligence, echoing Prov 3:19 ("the LORD by wisdom founded the earth; by understanding he established the heavens").</p>',
    "6": '<p><strong>lĕrōqaʿ hāʾāreṣ ʿal-hammayim kî lĕʿôlām ḥasdô</strong> — "to him who laid the earth out over the waters — for his steadfast love endures forever" — <em>rāqaʿ</em> (to beat out, hammer flat, spread out) — used of hammering metal into sheets (Num 16:39); applied here to spreading the solid earth over the primordial waters (Gen 1:9–10; Job 37:18). The image is of the earth as a surface hammered out over the cosmic deep — cosmological imagery used as praise language, not scientific description.</p>',
    "7": '<p><strong>lĕʿōśēh ʾôrîm gĕdōlîm kî lĕʿôlām ḥasdô</strong> — "to him who made the great lights — for his steadfast love endures forever" — <em>ʾôrîm gĕdōlîm</em> (great lights) — deliberately generic terms matching Gen 1:16\'s usage. The avoidance of <em>šemeš</em> (sun) and <em>yārēaḥ</em> (moon), which were also names of celestial deities in surrounding cultures, is a polemical move: these are not divine beings but lights the LORD created and assigned their governance.</p>',
    "8": '<p><strong>ʾet-haššemeš lĕmemšelet hayyôm kî lĕʿôlām ḥasdô</strong> — "the sun to govern the day — for his steadfast love endures forever" — <em>lĕmemšelet</em> (for the rule/governance of) — from <em>māšal</em> (to rule, have dominion); the sun governs the day as a delegated authority, not as an independent divine power. Gen 1:16 uses the identical language: the great light is set to rule the day.</p>',
    "9": '<p><strong>ʾet-hayyārēaḥ wĕkôkābîm lĕmemšĕlôt hallaylāh kî lĕʿôlām ḥasdô</strong> — "the moon and stars to govern the night — for his steadfast love endures forever" — the moon shares governance with the stars — neither having independent authority. The singular rule over night contrasts with the single sun; the pairing of moon and stars may reflect their combined use in ancient calendrical reckoning.</p>',
    "10": '<p><strong>lĕmakkēh miṣrayim bibkôrêhem kî lĕʿôlām ḥasdô</strong> — "to him who struck down Egypt by killing their firstborn — for his steadfast love endures forever" — the historical credo begins. <em>makkēh</em> (participle of <em>nākāh</em>, to strike/smite) — the Exodus narrative\'s defining verb for the plagues. <em>bibkôrêhem</em> (in/among their firstborn) — the final plague is specified; the death of the firstborn broke Pharaoh\'s resistance and released Israel. The psalmist frames these Exodus judgments as expressions of ḥesed: the very judgment against Egypt is simultaneously covenant loyalty to Israel.</p>',
    "11": '<p><strong>wayyôṣēʾ yiśrāʾēl mittôkām kî lĕʿôlām ḥasdô</strong> — "who led Israel out from among them — for his steadfast love endures forever" — <em>wayyôṣēʾ</em> (Hiphil consecutive of <em>yāṣāʾ</em>, cause to go out) — the paradigmatic Exodus verb; the same word in the Decalogue: "I am the LORD your God who brought you out (<em>yāṣāʾ</em>) of Egypt" (Exod 20:2). The leading out "from among them" (<em>mittôkām</em>) implies extraction from the midst of the Egyptians — the Exodus as liberation from a surrounding hostile environment.</p>',
    "12": '<p><strong>bĕyād ḥăzāqāh ûbizrōaʿ nĕṭûyāh kî lĕʿôlām ḥasdô</strong> — "with a powerful hand and an arm stretched wide — for his steadfast love endures forever" — <em>yād ḥăzāqāh</em> (strong hand) and <em>zĕrōaʿ nĕṭûyāh</em> (outstretched arm) — the formulaic pair from the Exodus tradition (Deut 4:34; 5:15; 7:19; 26:8; Ezek 20:33–34). The pair occurs so frequently in the Deuteronomic credo that it functions as a summary for the entire redemptive act. The "stretched arm" imagery invokes the warrior stance — YHWH fighting for Israel as their divine warrior.</p>',
    "13": '<p><strong>lĕgōzēr yam-sûp ligzārîm kî lĕʿôlām ḥasdô</strong> — "to him who split the Reed/Red Sea apart — for his steadfast love endures forever" — <em>gāzar</em> (to cut, split, divide) — the verb used for the sea\'s division; both <em>bāqaʿ</em> and <em>gāzar</em> emphasize a violent cleaving apart of the waters. <em>yam-sûp</em> (Sea of Reeds) — the Hebrew is "sea of reeds" (<em>sûp</em> = reeds, papyrus), likely the papyrus marshes at the northern Suez region rather than the deep Red Sea proper, though the tradition was rendered "Red Sea" in the LXX.</p>',
    "14": '<p><strong>wĕheʿěbîr yiśrāʾēl bĕtôkô kî lĕʿôlām ḥasdô</strong> — "who led Israel safely through its midst — for his steadfast love endures forever" — <em>heʿěbîr</em> (Hiphil of <em>ʿābar</em>, to cause to pass through) — the same root as the Passover crossing; Israel is led through the divided sea, not around it. The path through the midst of the sea is the signature miraculous act that generates the entire hymnic tradition (Exod 15; Ps 66:6; Isa 51:10).</p>',
    "15": '<p><strong>wĕniʿēr parʿōh wĕḥêlô bĕyam-sûp kî lĕʿôlām ḥasdô</strong> — "and swept Pharaoh and his army into the Reed Sea — for his steadfast love endures forever" — <em>niʿēr</em> (Piel of <em>nāʿar</em>, to shake off, to sweep away) — a verb of violent shaking; Pharaoh and his forces are shaken into the sea like crumbs shaken from a cloth. Exod 14:27 uses <em>nēʿar</em> for the same event: the LORD "threw" the Egyptians into the midst of the sea.</p>',
    "16": '<p><strong>lĕmôlîk ʿammô bammidbar kî lĕʿôlām ḥasdô</strong> — "to him who guided his people through the desert — for his steadfast love endures forever" — <em>mōlîk</em> (Hiphil participle of <em>hālak</em>, cause to walk, lead) — the forty-year wilderness period — with its rebellion, murmuring, and divine provision — is summarized in a single participial phrase and presented as an act of covenant ḥesed: YHWH guiding Israel through uninhabitable terrain.</p>',
    "17": '<p><strong>lĕmakkēh mĕlākîm gĕdōlîm kî lĕʿôlām ḥasdô</strong> — "to him who defeated great kings — for his steadfast love endures forever" — the conquest summary begins with the same participle (<em>makkēh</em>, striking/smiting) used for the Exodus plagues (v10), creating a structural parallel: the same divine warrior who struck Egypt struck the Canaanite kings.</p>',
    "18": '<p><strong>wayyahărōg mĕlākîm ʾaddîrîm kî lĕʿôlām ḥasdô</strong> — "who slew renowned kings — for his steadfast love endures forever" — <em>ʾaddîrîm</em> (renowned, majestic, powerful, from <em>ʾādar</em>, to be great, glorious) — a stronger term than <em>gĕdōlîm</em> (great); these are kings of distinction and renown. The escalation (great → renowned) prepares for the named exemplars in vv19–20.</p>',
    "19": '<p><strong>lĕSîḥôn melek hāʾĕmōrî kî lĕʿôlām ḥasdô</strong> — "Sihon, king of the Amorites — for his steadfast love endures forever" — Sihon denied Israel passage and was defeated at Jahaz (Num 21:21–25; Deut 2:26–37). His defeat opened the Transjordanian campaign. In the biblical tradition Sihon and Og became paradigmatic examples of YHWH\'s conquest power, cited together in Num 21, Deut 1–4, Josh 2, Neh 9, and Pss 135–136.</p>',
    "20": '<p><strong>ûlĕʿôg melek habbāšān kî lĕʿôlām ḥasdô</strong> — "and Og, king of Bashan — for his steadfast love endures forever" — Og, remembered for his enormous iron bed (Deut 3:11), was the last of the Rephaim. His defeat at Edrei (Num 21:33–35) completed Israel\'s control of Transjordan. The brevity of his mention signals how established the tradition was: the audience needed only the name to recall the full episode.</p>',
    "21": '<p><strong>wĕnātan ʾarṣām lĕnāḥălāh kî lĕʿôlām ḥasdô</strong> — "who gave their land as an inheritance — for his steadfast love endures forever" — <em>lĕnāḥălāh</em> (as an inheritance/heritage) — the goal of the conquest is not military glory but the inheritance promised to Abraham (Gen 15:18–21; 17:8). The land is received as inheritance, carrying both the legal weight of patrimonial property and the theological weight of covenant fulfillment.</p>',
    "22": '<p><strong>nāḥălāh lĕyiśrāʾēl ʿabdô kî lĕʿôlām ḥasdô</strong> — "an inheritance given to Israel his servant — for his steadfast love endures forever" — the repetition of <em>nāḥălāh</em> from v21 is a resumptive doublet (resumptio) that makes the inheritance emphatic by restating it with added specificity. <em>ʿabdô</em> (his servant, singular) — Israel collectively is YHWH\'s servant, recalling the Servant Songs of Isaiah and the covenant-servant language of Deut 32:36.</p>',
    "23": '<p><strong>šebekišpālēnû zākar lānû kî lĕʿôlām ḥasdô</strong> — "who remembered us when we were brought low — for his steadfast love endures forever" — <em>šebekišpālēnû</em> (when we were brought low, humiliated) — from <em>šāpēl</em> (to be low, humble), here Niphal participle: the humbled, abased state. <em>zākar lānû</em> (he remembered us) — the divine remembering (<em>zākar</em>) is active intervention; when God "remembers" in the Hebrew Bible he acts on behalf of the remembered (Gen 8:1; Exod 2:24). The verse shifts from historical narrative to confessional first-person plural, making the psalm contemporary for any generation in distress.</p>',
    "24": '<p><strong>wayyiprĕqēnû miṣṣārênû kî lĕʿôlām ḥasdô</strong> — "and delivered us from our enemies — for his steadfast love endures forever" — <em>yiprĕqēnû</em> (Hiphil of <em>pāraq</em>, to tear away, rescue by force, deliver) — a verb with connotations of violent rupture: the enemies\' grip is broken by force. <em>ṣārênû</em> (our adversaries, those who press us) — from <em>ṣārar</em> (to press, confine, be hostile).</p>',
    "25": '<p><strong>nōtēn leḥem lĕkol-bāśār kî lĕʿôlām ḥasdô</strong> — "who provides food for every living thing — for his steadfast love endures forever" — <em>kol-bāśār</em> (every flesh, every living creature) — the scope is universal, not restricted to Israel; the creational providence of v25 is broader than the covenant history of vv10–24. The psalm closes with creation before the final doxology (v26), forming a bracket with the creation section (vv4–9).</p>',
    "26": '<p><strong>hōdû lĕʾēl haššāmayim kî lĕʿôlām ḥasdô</strong> — "give thanks to the God of heaven — for his steadfast love endures forever" — <em>ʾēl haššāmayim</em> (God of heaven) — a title used in the post-exilic period and in Persian-era texts (Ezra 1:2; Neh 1:4; Dan 2:19) — which may indicate a late composition or adaptation. The closing call to thanks brackets the psalm with the opening <em>hōdû</em> (v1), and the 26th occurrence of <em>kî lĕʿôlām ḥasdô</em> closes the liturgical anthem. The number 26 matches the numerical value of the Tetragrammaton (YHWH) in gematria — whether intentional or coincidental, the structural completeness is striking.</p>',
  },
  "137": {
    "1": '<p><strong>ʿal naharôt bābel šām yāšabnû gam-bākînû bĕzākorēnû ʾet-ṣiyyôn</strong> — "by the rivers of Babylon we sat down and wept when we remembered Zion" — <em>naharôt bābel</em> (rivers of Babylon) — the Euphrates and the network of canals and irrigation channels in the Babylonian plain; the city was defined by its waterways. The verb pairing <em>yāšabnû gam-bākînû</em> (we sat and also wept) — <em>gam</em> (also, even) heightens the emotional weight: the sitting was accompanied by weeping, not silence. <em>bĕzākorēnû ʾet-ṣiyyôn</em> (when we remembered Zion) — the memory of Zion triggers weeping; <em>zākar</em> (remember) is active emotional recollection, not passive nostalgia. The exiles sit at the Babylonian waterways — a spatial antitype of sitting beside the waters of Zion (Ps 46:4).</p>',
    "2": '<p><strong>ʿal-ʿărābîm bĕtôkāh tālînû kinnōrôtênû</strong> — "we hung up our harps in the willow trees there" — <em>ʿărābîm</em> (willows, poplars; the Arabic-rooted word for "mixed stream" plant) — traditionally identified with willows or poplars along the riverbank. <em>kinnōrôtênû</em> (our lyres, not "harps") — the <em>kinnôr</em> is a small, hand-held stringed instrument, the instrument of David and Levitical temple music. Hanging the lyres on the trees is the gesture of musical suspension: the instruments are silenced. In the ancient Near East, hanging something high was a way of placing it beyond reach — the lyres were effectively retired while in exile.</p>',
    "3": '<p><strong>kî šām šĕʾēlûnû šôbênû dibrê-šîr wĕtôlālênû śimḥāh šîrû lānû miššîr ṣiyyôn</strong> — "for there our captors demanded songs; those who ruined us wanted entertainment: \'Sing us a song of Zion!\'" — <em>šôbênû</em> (our captors, those who took us captive) and <em>tôlālênû</em> (those who mocked/ruined us) — the double characterization of the oppressor. <em>šîr ṣiyyôn</em> (song of Zion) — a specific liturgical category celebrating Zion, Jerusalem, and YHWH\'s dwelling (Pss 46, 48, 76, 84, 87, 122). The captors\' demand for Zion songs as entertainment is doubly cruel: the songs are sacred, the context profane; they are being asked to perform holy worship as spectacle for their conquerors.</p>',
    "4": '<p><strong>ʾêk nāšîr ʾet-šîr-YHWH ʿal ʾadmat nēkār</strong> — "but how could we sing the LORD\'s song in a foreign land?" — <em>ʾêk</em> (how? — a question of impossibility, not mere difficulty) — the same word that opens Lamentations ("How does the city sit solitary…"). <em>šîr-YHWH</em> (song of the LORD) — not just a religious song but specifically the songs belonging to YHWH\'s liturgy. <em>ʾadmat nēkār</em> (soil of a foreigner/stranger) — from <em>nākar</em> (to treat as foreign, to be strange); the soil itself is alien. In ancient understanding, YHWH was particularly present in Israel\'s land; singing his liturgy on alien soil felt like a category violation.</p>',
    "5": '<p><strong>ʾim-ʾeškāḥēk yĕrûšālāim tiškaḥ yĕmînî</strong> — "if I forget you, O Jerusalem, may my right hand lose all skill" — <em>ʾeškāḥēk</em> and <em>tiškaḥ</em> — both from <em>šākaḥ</em> (to forget) — the verb appears in both halves of the oath. <em>yĕmînî tiškaḥ</em> (let my right hand forget) — a self-imprecatory oath: if I forget Jerusalem, may my right hand lose its skill at lyre-playing — the very skill the captors demanded. The right hand is the skilled hand for music and warfare; its "forgetting" is its disabling. The psalmist stakes their musical identity on their fidelity to Jerusalem.</p>',
    "6": '<p><strong>tidbaq-lĕšônî lĕḥikkî ʾim-lōʾ ʾezkĕrēkî ʾim-lōʾ ʾaʿăleh ʾet-yĕrûšālayim ʿal rōʾš śimḥātî</strong> — "if I do not hold you in memory, may my tongue stick to the roof of my mouth — if I do not place Jerusalem above my greatest delight" — <em>tidbaq-lĕšônî lĕḥikkî</em> (let my tongue stick to my palate) — the second self-imprecation, targeting the instrument of song; a silenced tongue cannot sing the captors\' demanded songs. <em>ʿal rōʾš śimḥātî</em> (above/at the head of my joy) — Jerusalem is not merely important but first in rank among all delights. This is the covenantal hierarchy of desire: the love of Zion ranks above personal happiness.</p>',
    "7": '<p><strong>zĕkōr YHWH libĕnê ʾĕdôm ʾēt yôm yĕrûšālāim hāʾōmĕrîm ʿārû ʿārû ʿad hayĕsôd bāh</strong> — "remember, O LORD, what Edom\'s sons did on the day Jerusalem fell — how they shouted, \'Tear it down! Tear it down to its very foundations!\'" — <em>zĕkōr YHWH</em> (remember, O LORD) — in Hebrew this is a call to action, not merely mental recollection; the psalmist calls for YHWH to act in judgment as he witnessed. <em>bĕnê ʾĕdôm</em> (sons of Edom) — Edom\'s collaboration with Babylon\'s destruction of Jerusalem was a deep wound in the exilic community (Obad 10–14; Ezek 25:12–14; Lam 4:21–22). <em>ʿārû ʿārû</em> (tear it down! tear it down!) — the repetition echoes the crowd\'s jeering cry. <em>hayĕsôd</em> (the very foundation) — <em>ʿad hayĕsôd bāh</em> (to its bedrock): complete, total demolition.</p>',
    "8": '<p><strong>bat-bābel hašĕdûdāh ʾašrê šeyyĕšallem-lāk ʾet-gĕmûlēk šeggāmalt lānû</strong> — "O Babylon, marked for destruction — how happy will be the one who pays you back for what you did to us!" — <em>bat-bābel</em> (daughter of Babylon) — the "daughter of" construction personifies a city as a woman, common in prophetic address (Jer 46:11; Lam 1:6; Zeph 3:14). <em>hašĕdûdāh</em> (the devastated, the one to be destroyed, Qal passive participle of <em>šādad</em>) — not yet destroyed but already addressed as condemned; prophetic judgment speaks the future as accomplished. <em>gĕmûlēk</em> (your repayment/recompense) — from <em>gāmal</em> (to deal out, repay, ripen); lex talionis applied to nations. <em>ʾašrê</em> (happy/blessed is) — the standard blessing formula (Ps 1:1) deployed in a strikingly harsh context; the one who carries out divinely-ordained retributive justice is declared "blessed."</p>',
    "9": '<p><strong>ʾašrê šeyyōʾḥēz wĕnippēaṣ ʾet-ʿōlālayik ʾel-hassālaʿ</strong> — "blessed is he who takes your little ones and smashes them against the rocks" — <em>ʿōlālayik</em> (your little ones, your infants) — the same category in Isa 13:16 (Babylon\'s children dashed in the announced fall of Babylon) and Nah 3:10 (Nineveh\'s infants). The verse is among the most troubling in the Psalter and requires honest engagement. First, it is a lament, not a command — the psalmist does not act; they cry out. Second, it reflects lex talionis at the national level: Babylon had done precisely this to Jerusalem\'s children (2 Kgs 25:7; Lam 4:3–4); the prayer is for proportional retribution. Third, Isa 13:16 makes this the announced judgment of YHWH against Babylon — the psalm prays the fulfillment of prophetic decree. Fourth, the rage is honest: the psalm refuses to spiritualize grief. The imprecation is not commended as Christian virtue but preserved as truthful testimony to what exile does to human beings — and as a text that shows the Psalter capable of bearing even the ugliest human prayer before God.</p>',
  },
  "138": {
    "1": '<p><strong>ʾôdĕkā bĕkol-libbî neged ʾĕlōhîm ʾăzammĕreka</strong> — "I will praise you, O LORD, with all my heart; in the presence of the heavenly assembly I will sing your praises" — <em>bĕkol-libbî</em> (with all my heart) — the <em>lēb</em> (heart) is in Hebrew thought the seat of will, intellect, and inner orientation; "all my heart" signals wholeness of devotion. <em>neged ʾĕlōhîm</em> (before/in the presence of gods) — the phrase is deliberately ambiguous: <em>ʾĕlōhîm</em> could refer to (a) pagan gods, before whom the psalmist defiantly praises YHWH; (b) the heavenly assembly or divine council (Ps 82:1; 89:7); or (c) a plural of majesty for God himself. The most probable reading in this context is (b) — the celestial assembly — making the praise a cosmic act witnessed by the heavenly court.</p>',
    "2": '<p><strong>ʾeštaḥăweh ʾel-hêkal qodšĕkā wĕʾôdeh ʾet-šimĕkā ʿal ḥasdĕkā wĕʿal ʾamittĕkā kî-higdaltā ʿal-kol-šimĕkā ʾimrātĕkā</strong> — "I will bow toward your holy temple and praise your name for your steadfast love and faithfulness; for you have exalted your word above even your own name" — <em>ḥasdĕkā wĕʾamittĕkā</em> (your steadfast love and your faithfulness/truth) — the paired terms of covenant character throughout the Psalter (Ps 25:10; 26:3; 36:5; 57:3; 115:1). <em>kî-higdaltā ʿal-kol-šimĕkā ʾimrātĕkā</em> — the most difficult clause in the psalm: "you have magnified your word/promise above all your name." The most defensible reading: the fulfillment of God\'s specific promise (<em>ʾimrāh</em>, word/promise/utterance) has proven greater than even the general reputation of his name — the concrete act of salvation exceeded the expectations created by his fame. The verse does not subordinate the name to the word in ontological rank but testifies that experience of God\'s word-keeping surpassed what his reputation alone had led the psalmist to expect.</p>',
    "3": '<p><strong>bĕyôm qārāʾtî watĕʿānēnî tarhĕbēnî bĕnapšî ʿōz</strong> — "on the day I called out, you answered me; you filled my soul with bold strength" — <em>bĕyôm qārāʾtî watĕʿānēnî</em> (in the day I called and you answered me) — the swift, personal response to prayer; not a delayed or conditional answer but an answered call. <em>tarhĕbēnî bĕnapšî ʿōz</em> — "you made my soul bold with strength" — <em>rāhab</em> (to be wide, broad, bold) in the Hiphil (cause to be broad): YHWH expanded the psalmist\'s inner capacity, creating boldness. The boldness (<em>ʿōz</em>, strength) is located in the <em>nepeš</em> — not physical strength added externally but inner fortitude produced in the whole self.</p>',
    "4": '<p><strong>yôdûkā YHWH kol-malkê ʾāreṣ kî šāmĕʿû ʾimrê pîkā</strong> — "all the kings of the earth will praise you, O LORD, when they hear the words you have spoken" — <em>kol-malkê ʾāreṣ</em> (all the kings of the earth) — the universal horizon; what began as personal praise (vv1–3) expands to encompass world rulers. <em>šāmĕʿû ʾimrê pîkā</em> (when they hear the words of your mouth) — the mechanism of universal praise is hearing the divine word, not coercion. The psalmist envisions a future in which YHWH\'s acts are so publicly demonstrated that even Gentile kings acknowledge him (cf. Ps 22:27–28; 86:9; Isa 45:22–23).</p>',
    "5": '<p><strong>wĕyāšîrû bĕdarkê YHWH kî gādôl kĕbôd YHWH</strong> — "they will sing of the paths of the LORD, for the glory of the LORD is great" — <em>darkê YHWH</em> (paths/ways of the LORD) — YHWH\'s characteristic ways of acting in the world; the pattern of his moral and redemptive governance. <em>kĕbôd YHWH</em> (the glory of the LORD) — <em>kābôd</em> (weight, heaviness, glory) — the manifest presence and honor of YHWH. The kings sing of his observable <em>dĕrākim</em>, which produces their recognition of his <em>kābôd</em>.</p>',
    "6": '<p><strong>kî rām YHWH wĕšāpāl yirʾeh wĕgābōah mimmĕrāḥāq yĕdāʿ</strong> — "though the LORD is exalted, he pays attention to the humble; but the arrogant he perceives from a distance" — <em>rām YHWH</em> (the LORD is high/exalted) — divine transcendence. <em>wĕšāpāl yirʾeh</em> (but the humble/lowly he sees) — the divine reversal motif central to the Psalter and the prophets: the exalted LORD sees downward toward the <em>šāpāl</em>. <em>gābōah mimmĕrāḥāq yĕdāʿ</em> (the haughty/high from afar he knows) — the proud receive only distant surveillance, not intimate attention. The reversal inverts human expectation: height should attract the high God\'s notice, but lowliness does instead (Isa 57:15; 66:2).</p>',
    "7": '<p><strong>ʾim-ʾēlēk bĕqereb ṣārāh tĕḥayyênî ʿal ʾap ʾōyĕbay tišlaḥ yādĕkā wĕtôšîʿēnî yĕmîněkā</strong> — "even when I walk through terrible trouble, you keep me alive; you reach out your hand against the fury of my enemies, and your right hand rescues me" — <em>bĕqereb ṣārāh</em> (in the midst of trouble/distress) — <em>ṣārāh</em> (distress, from <em>ṣārar</em>, to press/bind) — to walk "in the midst of" it means to be surrounded. <em>tĕḥayyênî</em> (you keep me alive, you revive me) — Piel of <em>ḥāyāh</em>, to preserve life, to quicken. <em>ʿal ʾap ʾōyĕbay</em> (against the anger of my enemies) — YHWH\'s hand is extended against the enemies\' wrath. <em>yĕmîněkā</em> (your right hand) — the right hand of a warrior holds the sword; YHWH\'s right hand is his saving power (Exod 15:6; Ps 118:15–16).</p>',
    "8": '<p><strong>YHWH yiglōr baʿădî YHWH ḥasdĕkā lĕʿôlām maʿăśê yādêkā ʾal-tereP</strong> — "the LORD will fulfill his purpose for me; your steadfast love, O LORD, endures forever — do not abandon what your hands have made" — <em>yiglōr</em> (Qal imperfect of <em>gāmar</em>, to complete, accomplish, bring to full term) — a rare verb: YHWH will "complete" on behalf of the psalmist. The psalm ends where it began: with <em>ḥasdĕkā lĕʿôlām</em> (your steadfast love forever) — the covenantal ground of all confidence. <em>maʿăśê yādêkā</em> (the work of your hands) — the psalmist appeals to their status as YHWH\'s own handiwork: you made me; do not let me be undone. <em>ʾal-tereP</em> (do not abandon/let go) — <em>rāpaʾ</em> (to relax, drop, forsake) in the Hiphil imperative; the prayer that the divine hand which made will not release.</p>',
  },
  "139": {
    "1": '<p><strong>YHWH ḥaqartanî watēdāʿ</strong> — "O LORD, you have searched me and you know me" — <em>ḥāqar</em> (H2713, to probe, examine thoroughly, penetrate) — from its basic meaning of digging through rock to examine ore, extended to intensive investigation; in the legal sphere, cross-examination; here applied to divine scrutiny of the inner person. The Qal perfect <em>ḥaqartanî</em> (you have searched me) presents the act as already accomplished: the search is complete and ongoing in its result. <em>watēdāʿ</em> (and you know) — the result of the search is full knowledge; not knowledge despite gaps, but comprehensive knowledge. This opening verse establishes the psalm\'s central theme: divine omniscience directed personally and intimately at the psalmist.</p>',
    "2": '<p><strong>ʾattāh yādaʿtā šibtî wĕqûmî bantāh lĕrēʿî mērāḥôq</strong> — "you know when I sit and when I stand; you understand my thoughts before I even form them" — <em>šibtî wĕqûmî</em> (my sitting and my rising) — a merism for all postures and activities; the two extremes of physical rest and motion encompass everything between. <em>bantāh lĕrēʿî mērāḥôq</em> — "you discern my thought from afar" — <em>rēaʿ</em> (thought, purpose, intention). <em>mērāḥôq</em> (from afar, from a distance) — before the thought is articulated or even fully formed, YHWH already perceives it from his transcendent vantage. The paradox of omniscient intimacy: God sees the innermost intention from a divine distance.</p>',
    "3": '<p><strong>ʾorḥî wĕrĕbî zērîtā wĕkol-dĕrākaî hiSkantāh</strong> — "you trace every path I walk and every place I rest; you are familiar with all my ways" — <em>ʾōraḥ</em> (path, way traveled) and <em>rebaʿ</em> (lying down, resting place) — the merism of movement and rest. <em>zērîtā</em> (you winnow/sift out, you measure) — from <em>zārāh</em> (to scatter, winnow, sift); YHWH sifts through the psalmist\'s paths as a farmer sifts grain — nothing passes unexamined. <em>hiSkantāh</em> (you are intimately familiar with) — from <em>sākan</em> (to be familiar with, accustomed to); YHWH has made himself thoroughly at home in the psalmist\'s ways.</p>',
    "4": '<p><strong>kî ʾên millāh bilĕšônî hēn YHWH yādaʿtā kullāh</strong> — "before a word is on my tongue, you know it completely, O LORD" — <em>ʾên millāh</em> (there is no word) — the word does not yet exist on the tongue; it is still unspoken. <em>hēn YHWH yādaʿtā kullāh</em> (behold, O LORD, you know it all/completely) — <em>hēn</em> (behold) signals the astonishing character of what follows; <em>kullāh</em> (all of it, the whole of it) is emphatic. YHWH knows the word before it has become a word at all — while it is still an intention seeking articulation.</p>',
    "5": '<p><strong>ʾāḥôr wāqedem ṣartanî watāšet ʿālay kappekā</strong> — "you surround me on every side — behind and before — and you have laid your hand upon me" — <em>ʾāḥôr wāqedem</em> (behind and before/east and west) — another merism for totality; in Hebrew orientation, <em>qedem</em> is east (the direction faced), so before + behind = east + west = all directions. <em>ṣartanî</em> (you have besieged me, you have pressed/enclosed me) — from <em>ṣûr</em> (to press, besiege, lay siege); the metaphor is military encirclement. <em>watāšet ʿālay kappekā</em> (you have laid your palm upon me) — <em>kap</em> (palm, hollow of the hand) — the resting of the divine palm: a gesture of both protection and constraint. The omnipresent God who encircles also touches.</p>',
    "6": '<p><strong>palʾiyyāh daʿat mimmennî niśgĕbāh lōʾ-ʾûkal lāh</strong> — "this knowledge is beyond me — too wonderful, too high for me to grasp" — <em>palʾiyyāh</em> (it is too wonderful, miraculous, Niphal participle of <em>pālāʾ</em>) — the root of <em>niplāʾôt</em> (wonders, miracles); the divine knowledge is classified in the same category as the Exodus miracles — beyond human capacity to achieve or comprehend. <em>niśgĕbāh</em> (it is too high, too lofty, Niphal of <em>śāgab</em>) — the knowledge is not merely intellectually difficult but ontologically beyond reach. The response to omniscience is not argument but awe.</p>',
    "7": '<p><strong>ʾānāh ʾēlēk mērûḥekā wĕʾānāh mippānêkā ʾebraḥ</strong> — "where can I go to escape your Spirit? Where can I flee from your presence?" — <em>rûaḥekā</em> (your Spirit, your breath) — the divine <em>rûaḥ</em> that fills all space; the omnipresence of YHWH expressed through his Spirit. <em>pānêkā</em> (your face, your presence) — the "face" of God is the expression of his active personal presence; to flee from the face is to attempt escape from the immediate divine attention (cf. Jonah 1:3, 10, using the same idiom). The rhetorical questions have no answer — the omnipresence is total. But the psalm\'s tone is wonder, not threat: the impossibility of escape is simultaneously the impossibility of abandonment.</p>',
    "8": '<p><strong>ʾim-ʾessaq šāmayim šām ʾattāh wĕʾaṣṣîʿāh šĕʾôl hinnekā</strong> — "if I rise to heaven, you are there; if I make my bed in the grave, you are there too" — <em>šāmayim</em> (heavens) — the highest accessible realm. <em>šĕʾôl</em> (Sheol) — the place of the dead, the underworld; in Hebrew cosmology the antipode of heaven. The merism heaven/Sheol encompasses the full vertical extent of the cosmos. <em>hinnekā</em> (there you are, behold you) — in both extremes YHWH is present. The theological significance: Sheol in the Hebrew Bible was sometimes imagined as beyond YHWH\'s reach (Ps 6:5; 88:5); Ps 139 corrects this — even the realm of the dead is not a zone of divine absence.</p>',
    "9": '<p><strong>ʾessāʾ kanpê-šāḥar ʾeškĕnāh bĕʾaḥărît hayyām</strong> — "if I fly away on the wings of the dawn and settle at the farthest edge of the sea" — <em>kanpê-šāḥar</em> (wings of the dawn/morning) — <em>šāḥar</em> (dawn, morning-light); the "wings" of the dawn are the spreading rays of light at sunrise, sweeping from east to west. The psalmist imagines riding this light to the farthest western horizon. <em>bĕʾaḥărît hayyām</em> (at the farthest end of the sea) — the western Mediterranean was the far horizon of the ancient Israelite world. The horizontal axis (east to west, dawn to sea\'s end) completes the directional coverage with the vertical axis (heaven to Sheol, v8) — omnipresence in all dimensions.</p>',
    "10": '<p><strong>gam-šām yādĕkā tanḥēnî wĕtōʾḥăzēnî yĕmînĕkā</strong> — "even there your hand will guide me, and your right hand will hold me fast" — <em>tanḥēnî</em> (Hiphil of <em>nāḥāh</em>, to guide, lead) — the same verb used for the divine guidance through the wilderness (Exod 15:13). <em>tōʾḥăzēnî yĕmînĕkā</em> (your right hand will hold me fast) — <em>ʾāḥaz</em> (to seize, grasp, hold); the "holding" is firm, not passive. The two hands — the guiding hand and the holding right hand — are the hands of shepherd and warrior simultaneously: the omnipresent God guides and secures.</p>',
    "11": '<p><strong>waʾōmar ʾak-ḥōšek yĕšûpēnî wĕlaylāh ʾôr baʿădênî</strong> — "if I say, \'The darkness will surely hide me, and the light around me turn to night\'" — <em>ʾak-ḥōšek yĕšûpēnî</em> (surely the darkness will cover/overwhelm me) — <em>šûp</em> is a rare verb; in Gen 3:15 it appears in the serpent/seed conflict ("he will strike/crush your head"). Here it may mean "overwhelm, engulf": the darkness will surely swallow me up. The psalmist voices the hypothetical attempt to use darkness as concealment from the divine presence — immediately refuted in v12.</p>',
    "12": '<p><strong>gam-ḥōšek lōʾ-yaḥšîk mimmekā wĕlaylāh kayyôm yāʾîr kĕḥōšekāh kāʾôrāh</strong> — "even the darkness is not dark to you; the night shines like the day, for darkness and light are the same to you" — <em>lōʾ-yaḥšîk mimmekā</em> (it is not dark from you, it does not grow dark before you) — <em>ḥāšak</em> (to be dark); the divine perception is not subject to the light spectrum available to humans. <em>kayyôm yāʾîr</em> (the night lights up like the day) — before YHWH\'s perceiving presence, the night is as transparent as day. <em>kĕḥōšekāh kāʾôrāh</em> (darkness as light to you) — the definitive statement of divine omniscience through the lens of light: no concealment is possible.</p>',
    "13": '<p><strong>kî-ʾattāh qānîtā kilyōtāy tĕsukēkēnî bĕbeṭen ʾimmî</strong> — "for you formed my inward parts; you wove me together in my mother\'s womb" — <em>qānîtā kilyōtāy</em> (you formed/acquired my kidneys) — <em>qānāh</em> (H7069, to create, erect, acquire/possess) — used of God\'s creating in Gen 14:19, 22 ("creator of heaven and earth") and Prov 8:22 ("the LORD possessed/created me"). <em>kilyôt</em> (kidneys, H3629) — the kidneys in Hebrew anthropology are the seat of the deepest emotions and moral sensibilities (Ps 7:9; 16:7; 26:2; Jer 11:20; 17:10) — what we would call the "gut" or conscience. YHWH formed the very organ of moral feeling. <em>tĕsukēkēnî</em> (you wove me together, covered me) — from <em>sāḵaḵ</em> (to weave, intertwine, cover as with a curtain); the body\'s intricate tissue is imaged as the embroiderer\'s skilled work. This verse provides the theological foundation for prenatal personhood in the psalm.</p>',
    "14": '<p><strong>ʾôdĕkā ʿal kî nôrāʾôt niplêtî niplāʾîm maʿăśêkā wĕnapšî yōdaʿat mĕʾōd</strong> — "I praise you because I am fearfully and wonderfully made — your works are marvellous, and my whole being knows it" — <em>nôrāʾôt</em> (fearfully, in an awe-inspiring manner) and <em>niplāʾîm</em> (wonderfully, in a wonder-producing manner) — both participial forms expressing the quality of the creation act. <em>niplêtî</em> (I am wonderfully made, Niphal perfect of <em>pālāʾ</em>) — the psalmist is the passive recipient of the wonderful making; the wonder belongs to the act, not the psalmist\'s subjective feeling. <em>wĕnapšî yōdaʿat mĕʾōd</em> (and my soul/whole being knows it very well) — the recognition of the wondrous making is located in the <em>nepeš</em> (the whole living self), not merely the intellect.</p>',
    "15": '<p><strong>lōʾ-nikad ʿaṣmî mimmekā ʾăšer-ʿuśśîtî basSēter rōqamtî bĕtaḥtiyyôt ʾāreṣ</strong> — "my very frame was not hidden from you when I was made in secret, skillfully crafted in the depths of the earth" — <em>ʿaṣmî</em> (my bones, my body-frame) — <em>ʿeṣem</em> can mean bone (structure) or the bodily self; here the physical structure in its making. <em>basSēter</em> (in the secret/hidden place) — the womb as a hidden place of formation; the "secret" is not concealment from God but the hidden depths of creaturely beginning. <em>rōqamtî</em> (I was skillfully crafted, embroidered, wrought with varied colors) — from <em>rāqam</em> (to embroider, weave in colored patterns, used of tabernacle textiles in Exod 26:36; 35:35); the body\'s intricate tissue and varied organ-structure is imaged as the embroiderer\'s skilled work. <em>bĕtaḥtiyyôt ʾāreṣ</em> (in the depths of the earth) — a poetic parallel to "in the womb"; the womb as the lowest hidden place of earth-bound existence.</p>',
    "16": '<p><strong>gālemî rāʾû ʿênêkā wĕʿal-siprekā kullām yikkātēbû yāmîm yuṣṣārû ûlō ʾeḥād bāhem</strong> — "your eyes saw my unformed body; all my days were written in your book before any of them had come to be" — <em>gōlemî</em> (my unformed mass, my embryo) — H1564, a hapax legomenon appearing only here in the entire Hebrew Bible. The root <em>gālam</em> means to wrap up; the <em>gōlem</em> is the wrapped, unformed embryonic mass before it has differentiated into recognizable form. YHWH saw the pre-formed embryo before it was recognizable as a person. <em>sēper</em> (book, scroll) — the divine record in which the psalmist\'s days are inscribed before they exist; a book of providential knowledge, not fatalistic predetermination but the comprehensive foreknowledge of the God who "completes" all things (Ps 138:8). <em>kullām yikkātēbû</em> (all of them were written) — the totality of days, written before any came into existence.</p>',
    "17": '<p><strong>ûlî mah-yāqĕrû rēʿêkā ʾēl mah ʿāṣĕmû rāʾšêhem</strong> — "how priceless are your thoughts toward me, O God! How immeasurable their total!" — <em>mah-yāqĕrû</em> (how precious/rare they are) — <em>yāqar</em> (to be precious, costly, honored; rare): the divine thoughts directed toward the psalmist are both precious and beyond ordinary occurrence. <em>rēʿêkā</em> (your thoughts, your plans, your purposes) — the plural of <em>rēaʿ</em> (thought, purpose, the directed cognitive act). <em>mah ʿāṣĕmû rāʾšêhem</em> (how vast their sum!) — an attempt to count the thoughts toward the psalmist would produce a sum too large to compute.</p>',
    "18": '<p><strong>ʾespĕrēm mēḥôl yirbûn hĕqîṣōtî wĕʿôdî ʿimmāk</strong> — "if I tried to count them, they would be more than the grains of sand; and when I wake, I am still with you" — <em>mēḥôl yirbûn</em> (they are more than sand) — the classic biblical hyperbole for uncountable number (Gen 22:17; 32:12; Isa 48:19). <em>hĕqîṣōtî wĕʿôdî ʿimmāk</em> (when I wake, I am still with you) — the stunning ending to the meditation on omnipresence: even after sleeping and waking, after all the contemplation has ended, the psalmist finds themselves still in the divine presence. The waking is not a new arrival into God\'s presence — it is the continuation of a presence that was never interrupted.</p>',
    "19": '<p><strong>ʾim-tiqṭōl ʾĕlōhîm rāšāʿ wĕʾanšê dāmîm sûrû mimmennî</strong> — "O God, if only you would put an end to the wicked! Get away from me, you murderers!" — the psalm pivots dramatically from meditation on omniscience (vv1–18) to imprecation against the wicked (vv19–22) before closing with self-examination (vv23–24). <em>tiqṭōl rāšāʿ</em> (slay the wicked) — the jussive prayer that God would remove the wicked; not the psalmist\'s act but God\'s. <em>ʾanšê dāmîm</em> (men of blood, murderers) — a technical term for violent offenders throughout the Psalter (Ps 5:6; 26:9; 55:23; 59:2; 2 Sam 16:7). The pivot is not arbitrary: the God who knows the psalmist perfectly (vv1–18) also knows the wicked perfectly — and the psalmist appeals to that omniscience for justice.</p>',
    "20": '<p><strong>ʾăšer yōmĕrûkā limzimmāh nāśūʾ laššāwĕʾ ʿārêkā</strong> — "they speak against you with evil intent; your adversaries invoke your name for nothing" — <em>limzimmāh</em> (for evil intent, for wicked scheme) — from <em>zimmāh</em> (devise, scheme, wickedness); the wicked\'s speech is not casual irreverence but deliberate plotting. <em>lāššāwĕʾ</em> (for falsehood, emptiness, vanity — the same <em>šāwĕʾ</em> of the third commandment: "do not take the name of the LORD in vain") — the wicked invoke YHWH\'s name for empty, false, or manipulative purposes.</p>',
    "21": '<p><strong>hălōʾ-mĕśanʾêkā YHWH ʾeśnāʾ ûbitqôměmêkā ʾetqôṭāṭ</strong> — "LORD, don\'t I hate those who hate you? Don\'t I despise those who rise up against you?" — <em>mĕśanʾêkā</em> (those who hate you) — <em>śānēʾ</em> (to hate, despise). The sentiment is not personal hatred but covenantal solidarity: to align with God is to align against what opposes him. This is the language of covenant loyalty, paralleling the Deuteronomic call to love what God loves and oppose what God opposes (Deut 7:9–10).</p>',
    "22": '<p><strong>tašlît śinʾāh śĕnēʾtîm lĕʾôyĕbîm hāyû lî</strong> — "I hate them with an absolute hatred; I number them among my enemies" — <em>tašlît śinʾāh śĕnēʾtîm</em> (with a complete/total hatred I hate them) — <em>tašlît</em> from <em>šālam</em> (to be whole, complete); the hatred is whole and undivided, without partial loyalty. <em>lĕʾôyĕbîm hāyû lî</em> (they have become enemies to me) — those who are enemies to YHWH are, by covenant solidarity, enemies of the psalmist. This verse is theologically difficult for Christian readers, who are called to love enemies (Matt 5:44). The psalm speaks within the OT covenantal framework; the NT transforms this framework by specifying a new way of dealing with personal enemies — without canceling the reality that opposition to God is serious.</p>',
    "23": '<p><strong>ḥāqĕrēnî ʾēl wĕdaʿ lĕbābî bĕḥānēnî ûdaʿ śarʿappāy</strong> — "search me, O God, and know my heart; put me to the test and see what I am thinking" — the prayer of vv23–24 invites upon the psalmist the very omniscient scrutiny that vv1–6 described as inevitable. <em>ḥāqĕrēnî</em> (search me, imperative of <em>ḥāqar</em>) — the same verb as v1; the psalmist actively summons the divine searching that was already described as ongoing. This is not confidence in personal righteousness but confidence that the God who sees completely will judge truly. <em>bĕḥānēnî</em> (test/try me, refine me) — from <em>bāḥan</em> (to test, refine as metals are refined); YHWH is invited to apply the refiner\'s examination. <em>śarʿappāy</strong> (my anxious thoughts, my disquieting thoughts, pl. of <em>śarʿap</em>) — the divided, branching thoughts that cause inner conflict and anxiety; the psalmist asks God to see even these.</p>',
    "24": '<p><strong>ûrĕʾēh ʾim-derek-ʿōṣeb bî ûnĕḥēnî bĕderek ʿôlām</strong> — "see if there is any harmful path in me, and lead me in the way that lasts forever" — <em>derek-ʿōṣeb</em> (a path of pain/sorrow, a grievous way) — <em>ʿōṣeb</em> (pain, sorrow, hurt) — a path characterized by anguish; the root may also connect to <em>ʿeṣeb</em> (idol), so the phrase could carry the sense of idolatrous ways. The psalmist does not ask to be declared innocent but asks God to identify any hidden harmful way — a posture of honest openness to divine judgment. <em>derek ʿôlām</em> (the way that lasts forever, the everlasting way) — <em>ʿôlām</em> (eternity, forever, of old); this may mean the ancient tried way (the covenant path of the ancestors) or the way that leads to eternal life — the two meanings coexist. The psalm that opened with divine searching closes with the human invitation of that searching — a movement from received omniscience to requested examination.</p>',
  },
}

def main():
    existing = load_comm('mkt-original', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-original', 'psalms', existing)
    print('Psalms 134–139 mkt-original written.')

if __name__ == '__main__':
    main()
